-- Tạo cơ sở dữ liệu cho trạm sạc xe điện Việt Nam
-- Dữ liệu đầy đủ cho tất cả 63 tỉnh thành với ~1000 trạm sạc

-- Tạo database
CREATE DATABASE IF NOT EXISTS v_electric_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE v_electric_db;

-- Bảng tỉnh/thành phố
CREATE TABLE provinces (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(100) NOT NULL UNIQUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Bảng đơn vị vận hành
CREATE TABLE operators (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(100) NOT NULL UNIQUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Bảng trạm sạc xe điện
CREATE TABLE charging_stations (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(200) NOT NULL,
    address TEXT NOT NULL,
    province VARCHAR(100) NOT NULL,
    district VARCHAR(100) NOT NULL,
    lat DECIMAL(10, 8) NOT NULL,
    lng DECIMAL(11, 8) NOT NULL,
    status ENUM('active', 'inactive', 'full') DEFAULT 'active',
    operator VARCHAR(100),
    phone VARCHAR(20),
    charger_type VARCHAR(100),
    power_rating VARCHAR(50),
    connector_type VARCHAR(100),
    price_per_kwh DECIMAL(10, 2),
    is_free BOOLEAN DEFAULT FALSE,
    operating_hours VARCHAR(100),
    amenities TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    
    INDEX idx_province (province),
    INDEX idx_district (district),
    INDEX idx_status (status),
    INDEX idx_operator (operator),
    INDEX idx_connector_type (connector_type),
    INDEX idx_location (lat, lng)
);

