-- Thêm Views, Stored Procedures và Indexes
CREATE VIEW station_stats AS
SELECT 
    province,
    COUNT(*) as total_stations,
    COUNT(CASE WHEN status = 'active' THEN 1 END) as active_stations,
    COUNT(CASE WHEN status = 'inactive' THEN 1 END) as inactive_stations,
    COUNT(CASE WHEN status = 'full' THEN 1 END) as full_stations,
    COUNT(CASE WHEN is_free = TRUE THEN 1 END) as free_stations,
    AVG(price_per_kwh) as avg_price_per_kwh
FROM charging_stations 
GROUP BY province
ORDER BY total_stations DESC;

-- Stored Procedure tìm trạm sạc gần nhất
DELIMITER //
CREATE PROCEDURE FindNearbyStations(
    IN user_lat DECIMAL(10,8),
    IN user_lng DECIMAL(11,8),
    IN search_radius INT DEFAULT 10,
    IN max_results INT DEFAULT 10
)
BEGIN
    SELECT 
        id,
        name,
        address,
        province,
        district,
        lat,
        lng,
        status,
        operator,
        phone,
        charger_type,
        power_rating,
        connector_type,
        price_per_kwh,
        is_free,
        operating_hours,
        amenities,
        (6371 * acos(cos(radians(user_lat)) * cos(radians(lat)) * cos(radians(lng) - radians(user_lng)) + sin(radians(user_lat)) * sin(radians(lat)))) AS distance_km
    FROM charging_stations
    WHERE status = 'active'
    HAVING distance_km <= search_radius
    ORDER BY distance_km ASC
    LIMIT max_results;
END //
DELIMITER ;

-- Indexes để tối ưu hiệu suất
CREATE INDEX idx_search ON charging_stations(province, district, status);
CREATE INDEX idx_status_operator ON charging_stations(status, operator);
CREATE INDEX idx_province_district ON charging_stations(province, district);
CREATE INDEX idx_location ON charging_stations(lat, lng);
CREATE INDEX idx_connector_type ON charging_stations(connector_type);
CREATE INDEX idx_free_stations ON charging_stations(is_free, status);

